bool solve(long long n) {
    std::string s = std::to_string(n);
    int sum = 0;
    int product = 1;
    for (char c : s) {
        int digit = c - '0';
        sum += digit;
        product *= digit;
    }
    long long total = sum + product;
    return n % total == 0;
}

